    SELECT 1 FROM (

    ) a WHERE a.day = CURRENT_DATE
)

SELECT TO_CHAR(a.day, 'YYYY-MM-DD')
FROM (

) a
WHERE TO_CHAR(a.day, 'YYYY-MM') = #{month}
ORDER BY a.day
